ALTER TABLE organizations ADD CONSTRAINT fk_organizations_to_parent_organizations FOREIGN KEY (parent_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION;
CREATE INDEX i_organization_parent ON organizations (parent_id);

ALTER TABLE organizations ADD COLUMN root_parent_id integer DEFAULT NULL;
